PLANS = {
 'choking-child': ['choking-child.lean','choking-child.blows','choking-child.fist','choking-child.thrusts','choking-child.cycle','choking-child.cpr'],
 'allergic-reaction': ['allergic.signs','allergic.grip','allergic.cap','allergic.inject','allergic.hold','allergic.rub','allergic.call','allergic.legs','allergic.second','allergic.hospital'],
 'drowning': ['drowning.rescue','drowning.check','shared.breaths-first','shared.recovery-child','drowning.warm','drowning.hospital'],
 'severe-bleeding': ['bleeding.barrier','bleeding.press','bleeding.layer','bleeding.raise','bleeding.notq','bleeding.warm'],
 'electric-shock': ['electric.power','electric.notouch','electric.check','shared.recovery-child','electric.burns','electric.hospital'],
 'seizure': ['seizure.calm','seizure.clear','seizure.norestrain','seizure.nomouth','shared.recovery-child','seizure.rest','seizure.doctor'],
 'burns': ['burns.stop','burns.cool','burns.remove','burns.nono','burns.cling','burns.warm'],
 'head-injury': ['head.still','head.signs','head.compress','head.watch','head.nomeds','head.rest'],
 'poisoning': ['poison.novomit','poison.wipe','poison.container','poison.note','poison.skin','poison.eye','shared.recovery-child'],
 'heatstroke': ['heat.shade','heat.cool','heat.sips','heat.warm','heat.noheat','heat.warmsips'],
 'fever': ['fever.thermo','fever.light','fever.fluids','fever.comfort','fever.noaspirin','fever.sponge','fever.signs'],
 'bite': ['bite.wash','bite.press','bite.dress','bite.doctor','bite.sting','bite.cool','bite.tick','bite.allergy'],
}
p = 'src/features/emergency/data/emergencies.js'
lines = io.open(p, encoding='utf-8').read().split('\n')
cur = None
idx = 0
applied = {}
for i, line in enumerate(lines):
    m = re.match(r"\s+id: '([a-z-]+)',", line)
    if m:
        cur = m.group(1)
        idx = 0
        continue
    if cur in PLANS and re.match(r"\s+\{ title: '", line):
        if idx < len(PLANS[cur]):
            lines[i] = line.replace('{ title:', "{ scene: '%s', title:" % PLANS[cur][idx], 1)
            applied[cur] = applied.get(cur, 0) + 1
            idx += 1
io.open(p, 'w', encoding='utf-8', newline='\n').write('\n'.join(lines))
print('scene keys applied:', applied)
